// ---------------------------------------------------------------------------
// Mock Cloudflare API Server
// ---------------------------------------------------------------------------

function startMockCfServer(
  responses: Record<string, { result: unknown; isCollection?: boolean }>,
): { url: string; server: Deno.HttpServer } {
  const server = Deno.serve({ port: 0, onListen() {} }, (req) => {
    const url = new URL(req.url);
    const path = url.pathname;

    for (
      const [pattern, { result, isCollection }] of Object.entries(responses)
    ) {
      if (path.includes(pattern)) {
        return Response.json({
          success: true,
          errors: [],
          messages: [],
          result,
          result_info: isCollection
            ? {
              page: 1,
              per_page: 50,
              total_count: Array.isArray(result) ? result.length : 1,
              total_pages: 1,
            }
            : undefined,
        });
      }
    }

    return Response.json({
      success: false,
      errors: [{ code: 404, message: "Not found" }],
      messages: [],
      result: null,
    });
  });

  const addr = server.addr as Deno.NetAddr;
  return { url: `http://localhost:${addr.port}`, server };
}

function installFetchMock(mockUrl: string): () => void {
  const originalFetch = globalThis.fetch;
  globalThis.fetch = (input, init) => {
    const reqUrl = typeof input === "string" ? input : input.toString();
    const newUrl = reqUrl.replace(
      "https://api.cloudflare.com/client/v4",
      mockUrl,
    );
    return originalFetch(newUrl, init);
  };
  return () => {
    globalThis.fetch = originalFetch;
  };
}

Deno.test({
  name: "workers-ai model: get_credit_balance fetches and writes resource",
  sanitizeResources: false,
  fn: async () => {
    const mockData = {
      "balance": 1,
      "first_topup_success": true,
      "has_default_payment_method": true,
      "payment_method": { "brand": "test-value", "last4": "test-value" },
      "topup_config": {
        "amount": 1,
        "disabledReason": "test-value",
        "error": "test-value",
        "lastFailedAt": 1,
        "threshold": 1,
      },
    };
    const { url, server } = startMockCfServer({
      "/ai-gateway/billing/credit-balance": { result: mockData },
    });
    const uninstall = installFetchMock(url);

    try {
      const { context, getWrittenResources } = createModelTestContext({
        globalArgs: { "apiToken": "test-token", "accountId": "acct-123" },
        definition: {
          id: "test-id",
          name: "test-workers-ai",
          version: 1,
          tags: {},
        },
      });

      const result = await (model.methods as Record<
        string,
        {
          execute: (
            args: Record<string, unknown>,
            ctx: unknown,
          ) => Promise<{ dataHandles: unknown[] }>;
        }
      >).get_credit_balance.execute({}, context);
      assertEquals(result.dataHandles.length, 1);

      const resources = getWrittenResources();
      assertEquals(resources.length, 1);
    } finally {
      uninstall();
      await server.shutdown();
    }
  },
});

